  1→import { useCallback, useState } from 'react';
  2→import './profilepostcards.css';
  3→import '../../Editor/editor.css';
  4→import { motion } from 'framer-motion';
  5→import { LexicalComposer } from '@lexical/react/LexicalComposer';
  6→import { HeadingNode, QuoteNode } from '@lexical/rich-text';
  7→import ImageNode from '../../Editor/nodes/ImageNode';
  8→import { RichTextPlugin } from '@lexical/react/LexicalRichTextPlugin';
  9→import LexicalErrorBoundary from '@lexical/react/LexicalErrorBoundary';
 10→import { ContentEditable } from '@lexical/react/LexicalContentEditable';
 11→import ToolBar from '../../Editor/Toolbar';
 12→import ImagePlugin from '../../Editor/nodes/Plugins/ImagePlugin';
 13→import { OnChangePlugin } from '@lexical/react/LexicalOnChangePlugin';
 14→import { HistoryPlugin } from '@lexical/react/LexicalHistoryPlugin';
 15→import { updateJournal } from '../../../../../API/Api';
 16→import { useAuth } from '../../../../Context/useAuth';
 17→import { BarLoader } from 'react-spinners';
 18→import { useQueryClient } from '@tanstack/react-query';
 19→
 20→const EditJournal = ({onClose, journalData}) => {
 21→    const {session, user} = useAuth();
 22→    const queryClient = useQueryClient();
 23→
 24→    const theme = {
 25→        paragraph: 'editor-paragraph',
 26→        heading: {
 27→            h1: 'editor-heading-h1',
 28→            h2: 'editor-heading-h2',
 29→            h3: 'editor-heading-h3',
 30→        },
 31→        quote: 'editor-quote',
 32→        text: {
 33→            bold: 'editor-text-bold',
 34→            italic: 'editor-text-italic',
 35→            underline: 'editor-text-underline',
 36→        }
 37→    }
 38→
 39→    const [title, setTitle] = useState(journalData?.title);
 40→    const [editorState , setEditorState] = useState(journalData?.content);
 41→    const [isUpdatingJournal, setIsUpdatingJournal] = useState(false);
 42→    const addUploadedImagePath = useCallback(() => {}, []);
 43→
 44→    const handleClickCloseEditor = (e) => {
 45→        e.stopPropagation();
 46→        onClose();
 47→    }
 48→
 49→    const saveEditJournal = async(e, journalId, journalContent, title) => {
 50→        e.stopPropagation();
 51→        const formdata = new FormData();
 52→        if(journalId){
 53→            formdata.append('journalId', journalId)
 54→        }
 55→        if(journalContent){
 56→            formdata.append('content', journalContent)
 57→        }
 58→        if(title){
 59→            formdata.append('title', title);
 60→        }
 61→
 62→        try {
 63→            setIsUpdatingJournal(true)
 64→            const message = await updateJournal(session?.access_token, formdata);
 65→            if(message){
 66→                console.log(message)
 67→            }
 68→
 69→            queryClient.invalidateQueries(['userJournals', user?.userData?.[0].id])
 70→
 71→            setIsUpdatingJournal(false)
 72→            setTitle(null)
 73→            setEditorState(null)
 74→            onClose();
 75→        } catch (error) {
 76→            console.error("Error updating journal:", error);
 77→        } finally {
 78→            setTitle(null)
 79→            setEditorState(null)
 80→            setIsUpdatingJournal(false)
 81→            onClose()
 82→        }
 83→    }
 84→
 85→    const onChange = useCallback((state) => {
 86→        const jsonb = JSON.stringify(state.toJSON());
 87→        setEditorState(jsonb);
 88→    }, [])
 89→
 90→    return(
 91→        <div className='editor-parent-container' onClick={handleClickCloseEditor}>
 92→            <motion.div
 93→                className='editor-container'
 94→                initial={{scale: 0, opacity: 0.8}}
 95→                animate={{scale: 1, opacity: 1}}
 96→                exit={{scale: 0.8, opacity: 0}}
 97→                transition={{type: 'spring', stiffness: 260, damping: 25}}
 98→                onClick={(e) => e.stopPropagation()}
 99→            >
100→                <div className='editor-close-bttn-container'>
101→                    <button
102→                        onClick={handleClickCloseEditor}
103→                        className='editor-close-bttn'
104→                        aria-label="Close editor"
105→                        title="Close"
106→                    >
107→                        <svg xmlns="http://www.w3.org/2000/svg" height="24px" viewBox="0 -960 960 960" width="24px" fill="currentColor"><path d="m256-200-56-56 224-224-224-224 56-56 224 224 224-224 56 56-224 224 224 224-56 56-224-224-224 224Z"/></svg>
108→                    </button>
109→                </div>
110→
111→                <input
112→                    value={title || ''}
113→                    onChange={(e) => setTitle(e.target.value)}
114→                    className='content-title-input'
115→                    type="text"
116→                    placeholder='Title'
117→                />
118→
119→                <LexicalComposer initialConfig={{
120→                    namespace: 'editContent',
121→                    theme: theme,
122→                    editable: true,
123→                    editorState: typeof journalData?.content === 'string'
124→                    ? journalData.content : JSON.stringify(journalData?.content),
125→                    nodes: [HeadingNode, ImageNode, QuoteNode],
126→                    onError(error){
127→                        throw error
128→                    },
129→                }}>
130→                    <div className="toolbar-wrapper">
131→                        <ToolBar addUploadedImagePath={addUploadedImagePath}/>
132→                    </div>
133→
134→                    <div className="editor-loader-wrapper">
135→                        {isUpdatingJournal && (
136→                            <BarLoader loading={isUpdatingJournal} width={'100%'} height={3} color="var(--accent-purple)" speedMultiplier={0.7}/>
137→                        )}
138→                    </div>
139→
140→                    <div className="editor-shell">
141→                        <RichTextPlugin
142→                            contentEditable={
143→                                <ContentEditable
144→                                    className="editor-input"
145→                                    aria-placeholder="Edit your post..."
146→                                    placeholder={<div className="editor-placeholder">Edit your post...</div>}
147→                                />
148→                            }
149→                            ErrorBoundary={LexicalErrorBoundary}
150→                        />
151→
152→                        <ImagePlugin addUploadedImagePath={addUploadedImagePath}/>
153→                        <HistoryPlugin/>
154→                        <OnChangePlugin onChange={onChange}/>
155→                    </div>
156→
157→                    <div className='editor-footer'>
158→                        <span></span>
159→                        <button
160→                            onClick={(e) => saveEditJournal(e, journalData?.id, editorState, title)}
161→                            className='editor-save-bttn'
162→                            disabled={isUpdatingJournal}
163→                        >
164→                            Save edit
165→                        </button>
166→                    </div>
167→                </LexicalComposer>
168→            </motion.div>
169→        </div>
170→    )
171→}
172→
173→export default EditJournal;
174→

  1→/* ── Editor text formats ── */
  2→.editor-text-bold {
  3→    font-weight: bold;
  4→}
  5→.editor-text-italic {
  6→    font-style: italic;
  7→}
  8→.editor-text-underline {
  9→    text-decoration: underline;
 10→}
 11→
 12→/* ── Editor container variables (derived from global theme) ── */
 13→.editor-container {
 14→    --editor-bg: var(--bg-elevated);
 15→    --editor-surface: var(--bg-secondary);
 16→    --editor-text: var(--text-primary);
 17→    --editor-border: var(--border-light);
 18→    --editor-accent: var(--accent-purple);
 19→}
 20→
 21→/* ── Overlay backdrop ── */
 22→.editor-parent-container {
 23→    display: flex;
 24→    justify-content: center;
 25→    align-items: center;
 26→    position: absolute;
 27→    width: 100%;
 28→    height: 100%;
 29→    background-color: var(--bg-overlay);
 30→    backdrop-filter: blur(25px);
 31→    z-index: 130;
 32→}
 33→
 34→/* ── Main editor card ── */
 35→.editor-container {
 36→    display: flex;
 37→    flex-direction: column;
 38→    width: 100%;
 39→    max-width: 720px;
 40→    height: 80%;
 41→    min-height: 0;
 42→    overflow: hidden;
 43→    background-color: var(--editor-bg);
 44→    color: var(--editor-text);
 45→    border-radius: 16px;
 46→    padding: 1rem 1.5rem;
 47→    box-shadow: var(--shadow-modal);
 48→}
 49→
 50→.editor-container.is-canvas-mode{
 51→    max-width: 1100px;
 52→    height: 92%;
 53→    overflow-y: auto;
 54→    overflow-x: hidden;
 55→    overscroll-behavior-y: contain;
 56→    -webkit-overflow-scrolling: touch;
 57→}
 58→
 59→.editor-mode-shell {
 60→    position: relative;
 61→    display: flex;
 62→    flex-direction: column;
 63→    flex: 1;
 64→    min-height: 0;
 65→    overflow: hidden;
 66→}
 67→
 68→.editor-mode-shell.is-canvas-mode {
 69→    overflow-y: auto;
 70→    overflow-x: hidden;
 71→    overscroll-behavior-y: contain;
 72→    -webkit-overflow-scrolling: touch;
 73→}
 74→
 75→/* ── Close button row ── */
 76→.editor-close-bttn-container {
 77→    display: flex;
 78→    width: 100%;
 79→    justify-content: flex-end;
 80→    align-items: center;
 81→}
 82→.editor-close-bttn {
 83→    display: flex;
 84→    align-items: center;
 85→    justify-content: center;
 86→    padding: 0.4rem;
 87→    border: none;
 88→    background: transparent;
 89→    border-radius: 50%;
 90→    cursor: pointer;
 91→    color: var(--text-muted);
 92→    transition: background-color 0.15s ease, color 0.15s ease, transform 0.15s ease;
 93→}
 94→.editor-close-bttn svg {
 95→    fill: var(--text-muted);
 96→    transition: fill 0.15s ease;
 97→}
 98→.editor-close-bttn:hover {
 99→    background-color: var(--bg-pill);
100→    color: var(--editor-text);
101→    transform: scale(1.05);
102→}
103→.editor-close-bttn:hover svg {
104→    fill: var(--editor-text);
105→}
106→
107→/* ── Title input ── */
108→.content-title-input {
109→    margin: 0.5rem 0;
110→    border: none;
111→    border-bottom: 2px solid transparent;
112→    background-color: transparent;
113→    font-size: 1.75rem;
114→    font-weight: 650;
115→    font-family: var(--font-serif);
116→    padding: 0.5rem 0.25rem;
117→    color: var(--editor-text);
118→    transition: border-color 0.25s ease;
119→}
120→.content-title-input::placeholder {
121→    color: var(--text-muted);
122→}
123→.content-title-input:focus {
124→    outline: none;
125→    border-bottom-color: var(--editor-accent);
126→}
127→
128→/* ── Toolbar (above content) ── */
129→.toolbar-wrapper {
130→    display: flex;
131→    align-items: center;
132→    border-top: 1px solid var(--editor-border);
133→    border-bottom: 1px solid var(--editor-border);
134→    padding: 0.35rem 0;
135→    margin-bottom: 0;
136→    position: sticky;
137→    top: 0;
138→    z-index: 5;
139→    background-color: var(--editor-bg);
140→}
141→.toolbar {
142→    display: flex;
143→    align-items: center;
144→    gap: 2px;
145→    width: 100%;
146→    flex-wrap: wrap;
147→}
148→.group {
149→    display: flex;
150→    align-items: center;
151→    gap: 2px;
152→}
153→.toolbar-divider {
154→    width: 1px;
155→    height: 20px;
156→    background-color: var(--editor-border);
157→    margin: 0 6px;
158→    flex-shrink: 0;
159→}
160→.toolbar-bttns {
161→    display: flex;
162→    width: fit-content;
163→    height: fit-content;
164→    justify-content: center;
165→    align-items: center;
166→    padding: 0.4rem;
167→    border-radius: 6px;
168→    cursor: pointer;
169→    transition: all 0.15s ease;
170→    user-select: none;
171→    color: var(--editor-text);
