 30→const ToolBar = ({addUploadedImagePath, onSwitchToCanvas}) =>{
 31→    const [editor] = useLexicalComposerContext();
 32→    const {session} = useAuth();
 33→    const colorPickerRef = useRef(null);
 34→
 35→    // Active state tracking
 36→    const [activeStates, setActiveStates] = useState(DEFAULT_ACTIVE_STATES);
 37→
 38→    const [showTextColorPicker, setShowTextColorPicker] = useState(false);
 39→    const [showHighlightColorPicker, setShowHighlightColorPicker] = useState(false);
 40→
 41→    const COLOR_PALETTE = [
 42→        { label: 'Default', value: null },
 43→        { label: 'Black', value: '#000000' },
 44→        { label: 'Dark Gray', value: '#4d4d4d' },
 45→        { label: 'Gray', value: '#888888' },
 46→        { label: 'Light Gray', value: '#bfbfbf' },
 47→        { label: 'Red', value: '#f44336' },
 48→        { label: 'Pink', value: '#e91e63' },
 49→        { label: 'Purple', value: '#9c27b0' },
 50→        { label: 'Deep Purple', value: '#673ab7' },
 51→        { label: 'Indigo', value: '#3f51b5' },
 52→        { label: 'Blue', value: '#2196f3' },
 53→        { label: 'Light Blue', value: '#03a9f4' },
 54→        { label: 'Cyan', value: '#00bcd4' },
 55→        { label: 'Teal', value: '#009688' },
 56→        { label: 'Green', value: '#4caf50' },
 57→        { label: 'Light Green', value: '#8bc34a' },
 58→        { label: 'Lime', value: '#cddc39' },
 59→        { label: 'Yellow', value: '#ffeb3b' },
 60→        { label: 'Amber', value: '#ffc107' },
 61→        { label: 'Orange', value: '#ff9800' },
 62→        { label: 'Deep Orange', value: '#ff5722' },
 63→        { label: 'Brown', value: '#795548' },
 64→        { label: 'Blue Gray', value: '#607d8b' },
 65→    ];
