 67→    const toCompactRgb = (value) => {
 68→        if (!value) return '';
 69→        return value.toLowerCase().replace(/\s+/g, '');
 70→    };
 71→
 72→    const normalizeColor = (value) => {
 73→        if (!value) return '';
 74→        const trimmed = value.trim().toLowerCase();
 75→        if (!trimmed.startsWith('#')) {
 76→            return toCompactRgb(trimmed);
 77→        }
 78→
 79→        let hex = trimmed.slice(1);
 80→        if (hex.length === 3) {
 81→            hex = hex.split('').map((char) => `${char}${char}`).join('');
 82→        }
 83→        if (hex.length !== 6) {
 84→            return trimmed;
 85→        }
 86→
 87→        const r = parseInt(hex.slice(0, 2), 16);
 88→        const g = parseInt(hex.slice(2, 4), 16);
 89→        const b = parseInt(hex.slice(4, 6), 16);
 90→
 91→        return `rgb(${r},${g},${b})`;
 92→    };
 93→
 94→    const isPaletteColorActive = (activeValue, paletteValue) => {
 95→        const normalizedActive = normalizeColor(activeValue);
 96→        if (!paletteValue) {
 97→            return !normalizedActive;
 98→        }
 99→        return normalizedActive === normalizeColor(paletteValue);
100→    };
101→
102→    // Register update listener for active state detection
103→    useEffect(() => {
104→        return editor.registerUpdateListener(({ editorState }) => {
105→            editorState.read(() => {
106→                const selection = $getSelection();
107→                if (!$isRangeSelection(selection)) {
108→                    setActiveStates(DEFAULT_ACTIVE_STATES);
109→                    return;
110→                }
111→
112→                const bold = selection.hasFormat('bold');
113→                const italic = selection.hasFormat('italic');
114→                const underline = selection.hasFormat('underline');
115→
116→                const anchorNode = selection.anchor.getNode();
117→                let element;
118→                try {
119→                    element = anchorNode.getKey() === 'root'
120→                        ? anchorNode
121→                        : anchorNode.getTopLevelElement() || anchorNode.getTopLevelElementOrThrow();
122→                } catch {
123→                    element = null;
124→                }
125→
126→                let heading = null;
127→                let quote = false;
128→                let alignment = 'left';
129→
130→                if (element) {
131→                    if ($isHeadingNode(element)) {
132→                        heading = element.getTag(); // 'h1', 'h2', 'h3'
133→                    }
134→                    if ($isQuoteNode(element)) {
135→                        quote = true;
136→                    }
137→                    const formatType = element.getFormatType?.();
138→                    if (formatType) {
139→                        alignment = formatType;
140→                    }
141→                }
142→
143→                const textColor = $getSelectionStyleValueForProperty(selection, 'color', '');
144→                const highlightColor = $getSelectionStyleValueForProperty(selection, 'background-color', '');
145→
146→                setActiveStates({
147→                    bold,
148→                    italic,
149→                    underline,
150→                    heading,
151→                    quote,
152→                    alignment,
153→                    textColor,
154→                    highlightColor,
155→                });
156→            });
157→        });
158→    }, [editor]);
159→
160→    useEffect(() => {
161→        const handleClickOutside = (event) => {
162→            if (!colorPickerRef.current) return;
163→            if (!colorPickerRef.current.contains(event.target)) {
164→                setShowTextColorPicker(false);
165→                setShowHighlightColorPicker(false);
166→            }
167→        };
168→        document.addEventListener('mousedown', handleClickOutside);
169→        return () => document.removeEventListener('mousedown', handleClickOutside);
170→    }, []);
171→
172→
173→    const applyTextFormat = (format) => {
174→        editor.dispatchCommand(FORMAT_TEXT_COMMAND, format)
175→    }
176→
177→    const applyTextStyle = useCallback((styles) => {
178→        const sanitizedStyles = Object.fromEntries(
179→            Object.entries(styles).map(([key, value]) => [key, value ?? ''])
180→        );
181→        editor.update(() => {
182→            const selection = $getSelection();
183→            if ($isRangeSelection(selection)) {
184→                $patchStyleText(selection, sanitizedStyles);
185→            }
186→        });
187→    }, [editor]);
188→
189→    //heading node (H1, H2, H3)
190→    const setHeading = (tag) => {
191→        editor.update(() => {
192→            const selection = $getSelection();
193→            if ($isRangeSelection(selection)) {
194→                const anchorNode = selection.anchor.getNode();
195→
196→                let element;
197→                try {
198→                    element = anchorNode.getKey() === 'root'
199→                        ? anchorNode
200→                        : anchorNode.getTopLevelElement() || anchorNode.getTopLevelElementOrThrow();
201→                } catch (e) {
202→                    console.error('Could not get top level element:', e);
203→                    return;
204→                }
205→
206→                if (!element) return;
207→
208→                const type = typeof element.getType === 'function' ? element.getType() : null;
209→
210→                if (type && type !== "paragraph" && type !== "heading" && type !== "root") {
211→                    return;
212→                }
213→
214→                const isActive = $isHeadingNode(element) && element.getTag() === tag;
215→
216→                $setBlocksType(selection, () =>
217→                    isActive ? $createParagraphNode() : $createHeadingNode(tag)
218→                );
219→            }
220→        })
221→    }
222→
223→    //align element
224→    const setAlignment = (value) => {
225→        editor.dispatchCommand(FORMAT_ELEMENT_COMMAND, value);
226→    }
227→
228→    //quote block (toggle)
